    author: partial.author || '',
    spaceRef: partial.spaceRef || '',  // free-text or breadcrumb like "Master Bedroom"
    linkedStage: partial.linkedStage || '',           /* Phase 5.4 — optional */
    linkedActivity: partial.linkedActivity || '',     /* Phase 5.4 — optional */
