/* ========================================================== */
/* === Phase 5.8 Piece 2 — Task state machine =============== */
/* ========================================================== */
/* Single source of truth for task statuses. Add new states here. */
const TASK_STATES = {
  todo:                       { code: 'todo',                       label: 'To do',          shortLabel: 'To do',     bg: 'bg-bone',       fg: 'ink-soft',      iconName: 'Circle',       isTerminal: false, isOpen: true,  isReview: false },
  in_progress:                { code: 'in_progress',                label: 'In progress',    shortLabel: 'WIP',       bg: 'bg-terra-soft', fg: 'text-terra',    iconName: 'Circle',       isTerminal: false, isOpen: true,  isReview: false },
  blocked:                    { code: 'blocked',                    label: 'Blocked',        shortLabel: 'Blocked',   bg: 'bg-terra-soft', fg: 'text-terra',    iconName: 'Lock',         isTerminal: false, isOpen: true,  isReview: false },
  submitted_for_review:       { code: 'submitted_for_review',       label: 'Awaiting review',shortLabel: 'In review', bg: 'bg-bone',       fg: 'text-terra',    iconName: 'Eye',          isTerminal: false, isOpen: true,  isReview: true  },
  rejected_back_to_progress:  { code: 'rejected_back_to_progress',  label: 'Rejected — rework', shortLabel: 'Rework', bg: 'bg-terra-soft', fg: 'text-terra',    iconName: 'RotateCcw',    isTerminal: false, isOpen: true,  isReview: false },
  approved_closed:            { code: 'approved_closed',            label: 'Approved · closed', shortLabel: 'Closed',  bg: 'bg-moss-soft',  fg: 'text-moss',     iconName: 'CheckCircle2', isTerminal: true,  isOpen: false, isReview: false },
  /* Legacy — old tasks marked "done" before Piece 2. Treat as terminal-closed for back-compat. */
  done:                       { code: 'done',                       label: 'Done',           shortLabel: 'Done',      bg: 'bg-moss-soft',  fg: 'text-moss',     iconName: 'CheckCircle2', isTerminal: true,  isOpen: false, isReview: false },
};

/* Helper — accepts a status code, returns the config (with safe fallback) */
function taskStateConfig(code) {
  return TASK_STATES[code] || TASK_STATES.todo;
}

/* Helper — true if task is in any "still active" state (pre-closed) */
function isTaskOpen(task) {
  return taskStateConfig(task.status).isOpen;
}

/* Helper — true if task is in a closed/terminal state (approved_closed OR legacy done) */
function isTaskClosed(task) {
  return taskStateConfig(task.status).isTerminal;
}

/* === Phase 7.2 — Auto-computed progress helpers ===
   Progress always rolls up from the leaves. The leaf is a checklist item.
   Tasks without checklist items fall back to a binary status check:
     done = 100%, anything else = 0%.
   Activities, stages, and project all average task progress upward.
   No status filtering — if a checklist item exists, it counts.
   To not count something, delete it. */

function computeTaskProgress(task) {
  if (!task) return 0;
  const items = Array.isArray(task.checklistItems) ? task.checklistItems : [];
  if (items.length === 0) {
    /* No checklist — binary on status */
    return isTaskClosed(task) ? 100 : 0;
  }
  const doneCount = items.filter((i) => i && i.done === true).length;
  return Math.round((doneCount / items.length) * 100);
}

function computeActivityProgress(activityLabel, allTasks) {
  if (!activityLabel || !Array.isArray(allTasks)) return 0;
  const tasks = allTasks.filter((t) => t && t.linkedActivity === activityLabel);
  if (tasks.length === 0) return 0;
  const sum = tasks.reduce((acc, t) => acc + computeTaskProgress(t), 0);
  return Math.round(sum / tasks.length);
}

function computeStageProgress(stageLabel, allTasks) {
  if (!stageLabel || !Array.isArray(allTasks)) return 0;
  const tasks = allTasks.filter((t) => t && t.linkedStage === stageLabel);
  if (tasks.length === 0) return 0;
  /* Average task progress directly — every task within the stage carries equal weight.
     This is simpler than weighting by activity and matches user expectation that
     "stage progress = how much of its work is done". */
  const sum = tasks.reduce((acc, t) => acc + computeTaskProgress(t), 0);
  return Math.round(sum / tasks.length);
}

function computeProjectProgress(project) {
  if (!project) return 0;
  const allTasks = (project._wizard && project._wizard.projectTasks) || [];
  if (allTasks.length === 0) {
    /* No tasks defined yet — fall back to whatever static value was set during onboarding */
    return typeof project.progress === 'number' ? project.progress : 0;
  }
  const sum = allTasks.reduce((acc, t) => acc + computeTaskProgress(t), 0);
  return Math.round(sum / allTasks.length);
}

/* Look up the current user's team member record by name match on profile.user.name. */
function resolveCurrentTeamMember(profile, masters) {
  if (!profile || !profile.user || !profile.user.name) return null;
  const name = profile.user.name;
  const team = (masters && masters.MasterTeamMembers) || [];
  return team.find((m) => m.value === name) || null;
}

/* === Phase 5.8 Piece 4 — Review-flow helpers === */

/* True if a task requires manager review on closure (delegated, not self-assigned) */
function taskNeedsReview(task) {
  if (!task) return false;
  const assignee = task.assigneeId;
  const assigner = task.assignedById;
  /* If either is missing or they match, no review required (self-assigned or legacy task) */
  if (!assignee || !assigner) return false;
  return assignee !== assigner;
}

/* Append a review-log entry to a task immutably. Returns the new task object. */
function appendReviewLog(task, entry) {
  const log = Array.isArray(task.reviewLog) ? task.reviewLog : [];
  return {
    ...task,
    reviewLog: [...log, {
      event: entry.event,
      byId: entry.byId || null,
      byName: entry.byName || '',
      at: entry.at || new Date().toISOString().slice(0, 10),
      notes: entry.notes || '',
    }],
  };
}

/* Apply a state transition to a task and append a log entry. */
function applyTaskTransition(task, transition, actor) {
  const today = new Date().toISOString().slice(0, 10);
  const actorId = actor && actor.id;
  const actorName = (actor && actor.name) || '';
  let updates = {};
  let logEntry = null;

  switch (transition) {
    case 'submit_for_review': {
      updates = {
        status: 'submitted_for_review',
        submissionNote: task.submissionNote || '',
        completedOn: today,
      };
      logEntry = { event: 'submitted', byId: actorId, byName: actorName, at: today, notes: updates.submissionNote };
      break;
    }
    case 'approve': {
      updates = {
        status: 'approved_closed',
        closedAt: today,
        closedById: actorId,
        rejectionReason: '',
      };
      logEntry = { event: 'approved', byId: actorId, byName: actorName, at: today, notes: '' };
      break;
    }
    case 'reject': {
      updates = {
        status: 'rejected_back_to_progress',
        completedOn: '',
      };
      logEntry = { event: 'rejected', byId: actorId, byName: actorName, at: today, notes: task.rejectionReason || '' };
      break;
    }
    case 'self_close': {
      /* Self-assigned shortcut — straight to approved_closed */
      updates = {
        status: 'approved_closed',
        completedOn: today,
        closedAt: today,
        closedById: actorId,
      };
      logEntry = { event: 'self_closed', byId: actorId, byName: actorName, at: today, notes: '' };
      break;
    }
    case 'reopen': {
      /* Move a closed task back to to-do */
      updates = {
        status: 'todo',
        completedOn: '',
        closedAt: '',
        closedById: null,
      };
      logEntry = { event: 'reopened', byId: actorId, byName: actorName, at: today, notes: '' };
      break;
    }
    case 'delegate': {
      /* Reassign task to a new team member.
         Caller passes target via task fields: assigneeId, assigneeName, dueDate (already merged).
         Reset review state — delegation is a fresh start. */
      const isReviewState = task.status === 'submitted_for_review' || task.status === 'rejected_back_to_progress' || task.status === 'approved_closed';
      updates = {
        assignedById: actorId,
        assignedAt: today,
        /* If task was in any review/closed state, reset to todo (fresh delegation) */
        ...(isReviewState ? { status: 'todo', completedOn: '', closedAt: '', closedById: null, submissionNote: '', rejectionReason: '' } : {}),
      };
      logEntry = {
        event: 'delegated',
        byId: actorId,
        byName: actorName,
        at: today,
        notes: task.assigneeName ? `to ${task.assigneeName}${task.delegationNote ? ' — ' + task.delegationNote : ''}` : (task.delegationNote || ''),
      };
      /* Strip the transient delegationNote field so it doesn't persist on the task */
      delete updates.delegationNote;
      break;
    }
    default:
      return task;
  }

  const next = { ...task, ...updates };
  /* Always strip transient field after the merge */
  delete next.delegationNote;
  return logEntry ? appendReviewLog(next, logEntry) : next;
}

/* === Phase 5.8 Piece 5 — Reminder helpers === */

/* Compute a reminder date N days before a due date. Returns ISO date string or ''. */
function reminderDateBefore(dueDate, daysBefore) {
  if (!dueDate) return '';
  const d = new Date(dueDate);
  if (isNaN(d.getTime())) return '';
  d.setDate(d.getDate() - daysBefore);
  return d.toISOString().slice(0, 10);
}

/* True if a task has an active reminder firing today or in the past, and isn't dismissed.
   "Active reminder window" = remindAt <= today, task is open, dueDate hasn't passed yet
   (overdue tasks are surfaced separately by the existing overdue logic). */
function reminderIsActive(task) {
  if (!task) return false;
  if (!task.remindAt) return false;
  if (task.reminderDismissed) return false;
  if (!isTaskOpen(task)) return false;
  const today = new Date().toISOString().slice(0, 10);
  if (task.remindAt > today) return false; /* Not yet due to remind */
  return true;
}

/* Days from today until the reminder fires. Negative = already in window. */
function daysUntilReminder(task) {
  if (!task || !task.remindAt) return null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const remind = new Date(task.remindAt);
  remind.setHours(0, 0, 0, 0);
  return Math.ceil((remind.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
}

function computeTaskMetrics(tasks) {
  const list = tasks || [];
  const today = new Date().toISOString().slice(0, 10);
  const open = list.filter((t) => isTaskOpen(t));
  const overdue = open.filter((t) => t.dueDate && t.dueDate < today).length;
  const closed = list.length - open.length;
  return {
    overdueTasks: overdue,
    openTasks: open.length,
    totalTasks: list.length,
    doneTasks: closed, /* keep field name for back-compat with existing call sites */
  };
}

/* ============================================================================
   ===== Phase 9.0.14 — cloneTasksFromMasters =================================
   ============================================================================
   Adopt-on-creation pattern:
   - Iterate every MasterActivity. Filter by linkedServiceType (universal OR matches project).
   - For each surviving activity, find all MasterTasks linked to it.
   - Clone each as a project task with: unique id, masterRef pointing to source MasterTask id,
     status='todo', empty assignee, original linkedStage / linkedActivity preserved.
   - If an activity has NO master tasks, still create a placeholder project task using
     the activity name (so the studio sees the activity row in the Journey card).
   - Return the flat array — no hierarchy yet, hierarchy is reconstructed at render time
     by Stage→Activity grouping in the Workflow tab and Journey stage cards.
   ============================================================================ */
function cloneTasksFromMasters(masters, projectServiceType, projectStages) {
  const masterActivities = (masters && masters.MasterActivities) || [];
  const masterTasks = (masters && masters.MasterTasks) || [];
  const cloned = [];
  const today = new Date().toISOString().slice(0, 10);

  /* Service-type filter: include if linkedServiceType is empty (universal) or matches project. */
  const serviceTypeMatches = (linkedSt) => {
    if (!linkedSt) return true;
    if (!projectServiceType) return false;
    return linkedSt === projectServiceType;
  };

  /* Iterate each master activity */
  masterActivities.forEach((activity) => {
    if (!serviceTypeMatches(activity.linkedServiceType)) return;
    if (!activity.value) return;

    /* Find tasks linked to this activity */
    const tasksUnder = masterTasks.filter((mt) => {
      if (!mt.linkedActivity) return false;
      return (mt.linkedActivity || '').toLowerCase() === (activity.value || '').toLowerCase()
          && serviceTypeMatches(mt.linkedServiceType);
    });

    if (tasksUnder.length > 0) {
      tasksUnder.forEach((mt) => {
        cloned.push({
          id: `tk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          title: mt.value,
          description: mt.description || '',
          linkedStage: activity.linkedStage || mt.linkedStage || '',
          linkedActivity: activity.value || '',
          assigneeId: null,
          assigneeName: '',
          assignedById: null,
          assignedAt: '',
          assignee: '',
          status: 'todo',
          dueDate: '',
          createdOn: today,
          completedOn: '',
          masterRef: mt.id,
          isClientVisible: false,
          isVendorVisible: false,
          isInternalOnly: false,
        });
      });
    } else {
      /* Activity has no master tasks — still create a placeholder so the activity is visible */
      cloned.push({
        id: `tk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        title: activity.value,
        description: activity.description || '(Placeholder task — no specific tasks defined for this activity in masters)',
        linkedStage: activity.linkedStage || '',
        linkedActivity: activity.value || '',
        assigneeId: null,
        assigneeName: '',
        assignedById: null,
        assignedAt: '',
        assignee: '',
        status: 'todo',
        dueDate: '',
        createdOn: today,
        completedOn: '',
        masterRef: null,
        isClientVisible: false,
        isVendorVisible: false,
        isInternalOnly: false,
      });
    }
  });

  return cloned;
}


/* ============================================================== */
/* === Phase 5.8 Piece 1c — Progress aggregation helpers ======= */
/* ============================================================== */

/* === Phase 5.9 Fix-pack — Array reorder helper ======= */
/* Move an item from one index to another, returning a new array. */
function reorderArray(arr, fromIdx, toIdx) {
  if (!Array.isArray(arr)) return arr;
  if (fromIdx === toIdx) return arr;
  if (fromIdx < 0 || fromIdx >= arr.length) return arr;
  if (toIdx < 0 || toIdx >= arr.length) return arr;
  const next = [...arr];
  const [moved] = next.splice(fromIdx, 1);
  next.splice(toIdx, 0, moved);
  return next;
}

/* === Phase 5.9 Fix-pack — "Used in" template scan =======
   Counts how many workflow templates reference a given master record by name.
   recordType: 'stage' | 'activity' | 'deliverable'
   For deliverables, we approximate via MasterDeliverables.linkedActivity matching
   any activity name that appears in any template — i.e. "would this deliverable
   auto-attach when a project picks any of these templates". */
function countUsageInTemplates(recordType, recordValue, masters) {
  const templates = (masters && masters.MasterWorkflowTemplates) || [];
  let count = 0;
  const referencingTemplates = [];

  templates.forEach((tmpl) => {
    const stages = tmpl.stages || [];
    let referenced = false;

    if (recordType === 'stage') {
      referenced = stages.some((s) => s.name === recordValue);
    } else if (recordType === 'activity') {
      referenced = stages.some((s) => (s.activities || []).includes(recordValue));
    } else if (recordType === 'deliverable') {
      /* Deliverable rows have a linkedActivity. The deliverable is "used by" a template
         iff any stage in that template includes that activity. */
      const allDeliverables = (masters && masters.MasterDeliverables) || [];
      const delRow = allDeliverables.find((d) => d.value === recordValue);
      if (delRow && delRow.linkedActivity) {
        referenced = stages.some((s) => (s.activities || []).includes(delRow.linkedActivity));
      }
    }

    if (referenced) {
      count++;
      referencingTemplates.push(tmpl.value);
    }
  });

  return { count, templates: referencingTemplates };
}

/* Compute derived progress % for a single activity, given the project's task list.
   Treats tasks and deliverables as equally-weighted units of work.
   Returns: { percent, taskTotal, taskClosed, deliverableTotal, deliverableApproved, totalUnits, closedUnits } */
function activityProgress(activity, projectTasks) {
  const activityTasks = (projectTasks || []).filter((t) => t.linkedActivity === activity.name);
  const taskTotal = activityTasks.length;
  const taskClosed = activityTasks.filter((t) => isTaskClosed(t)).length;

  const deliverables = activity.deliverables || [];
  const deliverableTotal = deliverables.length;
  const deliverableApproved = deliverables.filter((d) => d.status === 'approved').length;

  const totalUnits = taskTotal + deliverableTotal;
  const closedUnits = taskClosed + deliverableApproved;

  /* No work tracked yet → 0% (not "100% because there's nothing to do" — that would be misleading) */
  const percent = totalUnits > 0 ? Math.round((closedUnits / totalUnits) * 100) : 0;

  return { percent, taskTotal, taskClosed, deliverableTotal, deliverableApproved, totalUnits, closedUnits };
}

/* Compute derived progress for a stage by aggregating across its activities.
   Each activity contributes its own task+deliverable units; we sum and divide.
   Returns the same shape as activityProgress, plus activityCount. */
function stageProgress(stage, projectTasks) {
  const activities = stage.activities || [];
  let totalUnits = 0;
  let closedUnits = 0;
  let taskTotal = 0;
  let taskClosed = 0;
  let deliverableTotal = 0;
  let deliverableApproved = 0;

  activities.forEach((a) => {
    const ap = activityProgress(a, projectTasks);
    totalUnits += ap.totalUnits;
    closedUnits += ap.closedUnits;
    taskTotal += ap.taskTotal;
    taskClosed += ap.taskClosed;
    deliverableTotal += ap.deliverableTotal;
    deliverableApproved += ap.deliverableApproved;
  });

  const percent = totalUnits > 0 ? Math.round((closedUnits / totalUnits) * 100) : 0;

  return {
    percent, taskTotal, taskClosed, deliverableTotal, deliverableApproved,
    totalUnits, closedUnits, activityCount: activities.length,
  };
}

/* ============================================================== */
/* === Phase 5.8 Piece 6 — Performance metrics ================== */
/* ============================================================== */

/* Match a task to a team member.
   Prefers ID match (Phase 5.8 Piece 0+), falls back to legacy name string. */
function taskBelongsToMember(task, member) {
  if (!task || !member) return false;
  /* Primary assignee */
  if (task.assigneeId && member.id && task.assigneeId === member.id) return true;
  /* Phase 9.1.24 — Co-assignees count as primary belonging too. They can mark the task done. */
  if (Array.isArray(task.coAssigneeIds) && task.coAssigneeIds.map(String).includes(String(member.id))) return true;
  /* Legacy fallback — name string match (assignee + co-assignees) */
  const taskName = (task.assigneeName || task.assignee || '').trim().toLowerCase();
  const memberName = (member.value || '').trim().toLowerCase();
  if (taskName !== '' && taskName === memberName) return true;
  if (Array.isArray(task.coAssigneeNames) && task.coAssigneeNames.some((n) => (n || '').trim().toLowerCase() === memberName)) return true;
  return false;
}

/* Phase 9.1.24 — Manager attribution: a task counts toward this member's
   "tasks managed" tally when they are listed as the manager. Distinct from
   ownership. Used by Workload Analysis "as manager" roll-up. */
function taskManagedByMember(task, member) {
  if (!task || !member) return false;
  if (task.managerId && member.id && String(task.managerId) === String(member.id)) return true;
  const mgrName = (task.managerName || '').trim().toLowerCase();
  const memberName = (member.value || '').trim().toLowerCase();
  return mgrName !== '' && mgrName === memberName;
}

/* Phase 9.1.24 — Watcher attribution: read-only loop-ins. */
function taskWatchedByMember(task, member) {
  if (!task || !member) return false;
  if (Array.isArray(task.watcherIds) && task.watcherIds.map(String).includes(String(member.id))) return true;
  const memberName = (member.value || '').trim().toLowerCase();
  if (Array.isArray(task.watcherNames) && task.watcherNames.some((n) => (n || '').trim().toLowerCase() === memberName)) return true;
  return false;
}

/* Compute performance metrics for a single team member across ALL projects.
   Returns a structured object with counts, percentages, and a recent-activity list. */
function computeMemberPerformance(member, projects) {
  const today = new Date().toISOString().slice(0, 10);
  const todayTime = new Date(today).getTime();

  /* Flatten tasks across all projects, keeping projectId/name for context */
  const allTasks = [];
  (projects || []).forEach((p) => {
    const w = p._wizard || {};
    (w.projectTasks || []).forEach((t) => {
      if (taskBelongsToMember(t, member)) {
        allTasks.push({
          ...t,
          _projectId: p.id,
          _projectName: p.name,
          _projectAccent: p.accent,
        });
      }
    });
  });

  const total = allTasks.length;
  const open = allTasks.filter((t) => isTaskOpen(t));
  const closed = allTasks.filter((t) => isTaskClosed(t));
  const overdue = open.filter((t) => t.dueDate && t.dueDate < today);

  /* Closed on time vs late: prefer closedAt over completedOn (Phase 5.8 Piece 4 split these) */
  let closedOnTime = 0;
  let closedLate = 0;
  let totalLatenessDays = 0;
  let totalCloseTimeDays = 0;
  let closeTimeSampleCount = 0;

  closed.forEach((t) => {
    const closeDate = t.closedAt || t.completedOn;
    if (!closeDate) {
      /* Closed but no close date — shouldn't happen but guard */
      return;
    }
    if (!t.dueDate) {
      /* No due date — count as on-time (no missed deadline) */
      closedOnTime++;
    } else if (closeDate <= t.dueDate) {
      closedOnTime++;
    } else {
      closedLate++;
      const lateDays = Math.ceil((new Date(closeDate).getTime() - new Date(t.dueDate).getTime()) / (1000 * 60 * 60 * 24));
      totalLatenessDays += lateDays;
    }

    /* Average time to close — from assigned date or created date to close date */
    const startDate = t.assignedAt || t.createdOn;
    if (startDate) {
      const days = Math.max(0, Math.ceil((new Date(closeDate).getTime() - new Date(startDate).getTime()) / (1000 * 60 * 60 * 24)));
      totalCloseTimeDays += days;
      closeTimeSampleCount++;
    }
  });

  /* Rejections received at review — count entries in any task's reviewLog where this member was the doer */
  let rejectionsReceived = 0;
  allTasks.forEach((t) => {
    const log = Array.isArray(t.reviewLog) ? t.reviewLog : [];
    log.forEach((entry) => {
      if (entry.event === 'rejected') rejectionsReceived++;
    });
  });

  const closedTotal = closedOnTime + closedLate;
  const onTimePercent = closedTotal > 0 ? Math.round((closedOnTime / closedTotal) * 100) : null;
  const avgLatenessDays = closedLate > 0 ? Math.round(totalLatenessDays / closedLate) : 0;
  const avgCloseTimeDays = closeTimeSampleCount > 0 ? Math.round(totalCloseTimeDays / closeTimeSampleCount) : null;

  /* Recent — last 10 tasks sorted by most recent activity (close date or assigned date) */
  const recent = [...allTasks]
    .sort((a, b) => {
      const aDate = a.closedAt || a.completedOn || a.assignedAt || a.createdOn || '';
      const bDate = b.closedAt || b.completedOn || b.assignedAt || b.createdOn || '';
      return bDate.localeCompare(aDate);
    })
    .slice(0, 10);

  return {
    total,
    openCount: open.length,
    closedCount: closed.length,
    overdueCount: overdue.length,
    closedOnTime,
    closedLate,
    onTimePercent,         /* null when no closed tasks */
    avgLatenessDays,
    avgCloseTimeDays,      /* null when no closed tasks */
    rejectionsReceived,
    recent,
  };
}

